---@type LazyPluginSpec
return {
    "b0o/incline.nvim",
    event = "VeryLazy",
    config = function()
        local helpers = require("incline.helpers")

        require("incline").setup({
            --- Position at bottom so it doesn't compete with the winbar (path + breadcrumbs at top)
            window = {
                placement = {
                    vertical = "bottom",
                    horizontal = "right",
                },
                margin = { horizontal = 0, vertical = 0 },
                padding = 0,
            },
            render = function(props)
                local filename = vim.fn.fnamemodify(vim.api.nvim_buf_get_name(props.buf), ":t")
                if filename == "" then
                    filename = "[No Name]"
                end
                local icon, icon_hl = require("mini.icons").get("file", filename, { default = true })
                local modified = vim.bo[props.buf].modified

                return {
                    icon and { " ", icon, " ", group = icon_hl } or "",
                    " ",
                    { filename, gui = modified and "bold,italic" or "bold" },
                    " ",
                }
            end,
        })
    end,
}
